def clean_metadata(raw_data):
    def is_active(d):
        if isinstance(d.get("active"), bool): return d.get("active")
        if d.get("state") in ("active", "in_stock"): return True
        if d.get("status") in ("active", "ACTIVE"): return True
        if d.get("status") in ("discontinued", "DISCONTINUED"): return False
        return False

    return [
        {
            "id": int(d.get("id", d.get("prod_id", 0))),
            "name": d.get("name", d.get("prod_name", d.get("product", ""))),
            "price": float(d.get("price", d.get("price_usd", d.get("cost", 0))),
            "active": is_active(d)
        }
        for d in raw_data
    ]
